import dataclasses
import json


@dataclasses.dataclass(frozen=True)
class Config:
    title: str = "Report"
    output_format: str = "text"  # "text" or "markdown"
    max_rows: int = 10
    include_summary: bool = True


_KNOWN_KEYS = {f.name for f in dataclasses.fields(Config)}


def load_config(path):
    """Load config from a JSON file, filling in defaults for missing keys.

    Raises ValueError if the file contains an unknown setting.
    """
    with open(path) as f:
        raw = json.load(f)
    unknown = set(raw) - _KNOWN_KEYS
    if unknown:
        raise ValueError(f"Unknown config key(s): {', '.join(sorted(unknown))}")
    return Config(**raw)

