    Raises ValueError if the file contains an unknown setting.
    """
    with open(path) as f:
        raw = json.load(f)
    unknown = set(raw) - _KNOWN_KEYS
    if unknown:
        raise ValueError(f"Unknown config key(s): {', '.join(sorted(unknown))}")
    return Config(**raw)

